function matrixAddition(n, m, a, b) {
    const result = [];  // To store the result of matrix addition

    for (let i = 0; i < n; i++) {
        const row = [];
        for (let j = 0; j < m; j++) {
            row.push(a[i][j] + b[i][j]);  // Add corresponding elements from matrices a and b
        }
        result.push(row);
    }

    // Output each row on a new line
    result.forEach(row => console.log(row.join(' ')));
}
